const items = $input.all();
const now = new Date();
const processedMeetings = [];

for (const item of items) {
  const meeting = item.json;
  const startTime = new Date(meeting.start?.dateTime || meeting.start?.date);
  const hoursUntil = (startTime - now) / (1000 * 60 * 60);

  // 只處理1~3小時內即將開始的會議
  if (hoursUntil > 0 && hoursUntil <= 3) {
    processedMeetings.push({
      json: {
        id: meeting.id,
        summary: meeting.summary || '(無標題會議)',
        description: meeting.description || '',
        startTime: meeting.start?.dateTime || meeting.start?.date,
        endTime: meeting.end?.dateTime || meeting.end?.date,
        attendees: meeting.attendees || [],
        location: meeting.location || '線上會議',
        hoursUntil: Number(hoursUntil.toFixed(1)),
        meetingLink: meeting.hangoutLink ||
                     meeting.conferenceData?.entryPoints?.[0]?.uri ||
                     meeting.location || ''
      }
    });
  }
}

return processedMeetings;

// 組合提醒郵件 HTML 內容
const meeting = $('篩選1-3小時內會議').item.json;
const aiContent = $input.first().json.message?.content || $input.first().json.content || $input.first().json.text || '（AI建議產生失敗，請手動確認）';

const attendeeEmails = meeting.attendees
  .filter(a => a.email)
  .map(a => a.email)
  .join(', ');

const startFormatted = new Date(meeting.startTime).toLocaleString('zh-TW', {
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', hour12: false
});

const aiHtml = aiContent
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\n/g, '<br>');

const emailHtml = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body { font-family: Arial, sans-serif; color: #333; max-width: 600px; margin: 0 auto; padding: 20px; }
  .header { background: linear-gradient(135deg, #1F3864, #2E75B6); color: white; padding: 20px 24px; border-radius: 8px 8px 0 0; }
  .header h2 { margin: 0; font-size: 20px; }
  .header p { margin: 6px 0 0; opacity: 0.85; font-size: 13px; }
  .body { background: #f9fbfd; border: 1px solid #d0e0f0; border-top: none; border-radius: 0 0 8px 8px; padding: 20px 24px; }
  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 18px; }
  .info-table td { padding: 8px 10px; font-size: 14px; }
  .info-table .label { background: #e8f0fb; font-weight: bold; color: #1F3864; width: 110px; border-radius: 4px; }
  .ai-box { background: #fff; border-left: 4px solid #2E75B6; padding: 14px 16px; border-radius: 0 6px 6px 0; margin-top: 4px; font-size: 13px; line-height: 1.7; }
  .section-title { font-size: 15px; font-weight: bold; color: #1F3864; margin: 18px 0 8px; }
  .countdown { display: inline-block; background: #FF6B35; color: white; padding: 4px 12px; border-radius: 20px; font-weight: bold; font-size: 13px; }
  .footer { text-align: center; font-size: 11px; color: #999; margin-top: 20px; }
  .btn { display: inline-block; background: #2E75B6; color: white; padding: 10px 20px; border-radius: 6px; text-decoration: none; font-size: 14px; margin-top: 12px; }
</style>
</head>
<body>
<div class="header">
  <h2>📅 會議提醒通知</h2>
  <p>您有一場會議即將開始，請做好準備</p>
</div>
<div class="body">
  <span class="countdown">⏰ ${meeting.hoursUntil} 小時後開始</span>
  <table class="info-table" style="margin-top:14px">
    <tr><td class="label">會議主題</td><td>${meeting.summary}</td></tr>
    <tr><td class="label">開始時間</td><td>${startFormatted}</td></tr>
    <tr><td class="label">地點 / 連結</td><td>${meeting.location}</td></tr>
    ${meeting.meetingLink && meeting.meetingLink !== meeting.location ? `<tr><td class="label">會議連結</td><td><a href="${meeting.meetingLink}" style="color:#2E75B6">${meeting.meetingLink}</a></td></tr>` : ''}
    ${meeting.description ? `<tr><td class="label">會議說明</td><td>${meeting.description}</td></tr>` : ''}
  </table>
  <div class="section-title">🤖 AI 會議助理建議</div>
  <div class="ai-box">${aiHtml}</div>
  ${meeting.meetingLink ? `<a class="btn" href="${meeting.meetingLink}">立即加入會議</a>` : ''}
</div>
<div class="footer">此為自動提醒郵件，由 n8n 會議助理系統發送</div>
</body>
</html>`;

return [{
  json: {
    to: attendeeEmails,
    subject: `⏰ 會議提醒：${meeting.summary}（${meeting.hoursUntil} 小時後）`,
    html: emailHtml,
    meetingId: meeting.id,
    meetingTitle: meeting.summary,
    meetingTime: meeting.startTime,
    meetingEndTime: meeting.endTime,
    reminderSentAt: new Date().toISOString(),
    attendeeCount: meeting.attendees.length
  }
}];

